    protected function organizationSelectors(): array
    {
        $service = $this->orgUnitRuleService();
        $options = $service->hierarchyOptions();
        $tree = $service->hierarchyTree();
        $managedBranchIds = $this->managedBranchIds($service);

        if (is_array($managedBranchIds)) {
            if (empty($managedBranchIds)) {
                $options = collect();
                $tree = [];
            } else {
                $options = $options
                    ->filter(function ($unit) use ($managedBranchIds) {
                        return in_array((int) $unit->id, $managedBranchIds, true);
                    })
                    ->values();
                $tree = $this->filterHierarchyTreeByAllowedIds($tree, $managedBranchIds);
            }
        }

        return [
            'options' => $options,
            'tree' => $tree,
        ];
    }

    protected function organizationalUnits()
    {
        $query = Department::query()
            ->withoutGlobalScopes()
            ->with('unitType')
            ->where('is_active', true)
            ->orderByRaw('COALESCE(sort_order, 999999) asc')
            ->orderBy('department_name');

        $managedBranchIds = $this->managedBranchIds($this->orgUnitRuleService());
        if (is_array($managedBranchIds)) {
            if (empty($managedBranchIds)) {
                $query->whereRaw('1=0');
            } else {
                $query->whereIn('id', $managedBranchIds);
            }
        }

        return $query->get();
    }

