    public function exportExcel(Request $request, OrgUnitRuleService $orgUnitRuleService)
    {
        $query = Employee::query()
            ->where('employees.is_active', 1)
            ->with([
                'position',
                'gender',
                'department',
                'sub_department',
                'currentPayGradeHistory.payLevel',
                'latestPayGradeHistory.payLevel',
            ]);

        $this->applyManagedBranchScope($query, $this->managedBranchIds($orgUnitRuleService));

        $employeeName = $request->get('employee_name');
        $department = $request->get('department');
        $designation = $request->get('designation');
        $officialId10 = trim((string) $request->get('official_id_10', ''));
        $workStatusName = trim((string) $request->get('work_status_name', ''));
        $gender = $request->get('gender');
        $search = trim((string) $request->get('search', ''));

        $query
            ->when($employeeName, function ($q) use ($employeeName) {
                return $q->where('id', $employeeName);
            })
            ->when($department, function ($q) use ($department, $orgUnitRuleService) {
                $branchIds = $orgUnitRuleService->branchIdsIncludingSelf((int) $department);
                return $q->where(function ($w) use ($branchIds) {
                    $w->whereIn('department_id', $branchIds)
                        ->orWhereIn('sub_department_id', $branchIds);
                });
            })
            ->when($designation, function ($q) use ($designation) {
                return $q->where('position_id', $designation);
            })
            ->when($officialId10 !== '', function ($q) use ($officialId10) {
                return $q->where('official_id_10', 'like', '%' . $officialId10 . '%');
            })
            ->when($workStatusName !== '', function ($q) use ($workStatusName) {
                return $q->where('work_status_name', $workStatusName);
            })
            ->when($gender, function ($q) use ($gender) {
                return $q->where('gender_id', $gender);
            })
            ->when($search !== '', function ($q) use ($search) {
                $q->where(function ($w) use ($search) {
                    $w->where('official_id_10', 'like', '%' . $search . '%')
                        ->orWhere('first_name', 'like', '%' . $search . '%')
                        ->orWhere('last_name', 'like', '%' . $search . '%')
                        ->orWhere('middle_name', 'like', '%' . $search . '%')
                        ->orWhere('phone', 'like', '%' . $search . '%')
                        ->orWhere('work_status_name', 'like', '%' . $search . '%')
                        ->orWhereHas('position', function ($p) use ($search) {
                            $p->where('position_name', 'like', '%' . $search . '%')
                                ->orWhere('position_name_km', 'like', '%' . $search . '%');
                        })
                        ->orWhereHas('department', function ($d) use ($search) {
                            $d->where('department_name', 'like', '%' . $search . '%');
                        })
                        ->orWhereHas('sub_department', function ($d) use ($search) {
                            $d->where('department_name', 'like', '%' . $search . '%');
                        });
                });
            });

        $employees = $query
            ->leftJoin('positions as p_order', 'employees.position_id', '=', 'p_order.id')
            ->leftJoin('departments as d_main', 'employees.department_id', '=', 'd_main.id')
            ->leftJoin('departments as d_sub', 'employees.sub_department_id', '=', 'd_sub.id')
            ->select('employees.*')
            ->orderByRaw("CASE WHEN COALESCE(NULLIF(d_sub.location_code, ''), NULLIF(d_main.location_code, '')) LIKE 'LEGACY-WP-%' THEN 0 ELSE 1 END ASC")
            ->orderByRaw("CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(REPLACE(COALESCE(NULLIF(d_sub.location_code, ''), NULLIF(d_main.location_code, '')), 'LEGACY-WP-', ''), '-', 3), '-', -1) AS UNSIGNED) ASC")
            ->orderByRaw("CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(REPLACE(COALESCE(NULLIF(d_sub.location_code, ''), NULLIF(d_main.location_code, '')), 'LEGACY-WP-', ''), '-', 4), '-', -1) AS UNSIGNED) ASC")
            ->orderByRaw("CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(REPLACE(COALESCE(NULLIF(d_sub.location_code, ''), NULLIF(d_main.location_code, '')), 'LEGACY-WP-', ''), '-', 5), '-', -1) AS UNSIGNED) ASC")
            ->orderByRaw('COALESCE(d_main.sort_order, 0) ASC')
            ->orderByRaw("COALESCE(NULLIF(d_main.department_name, ''), '') ASC")
            ->orderByRaw('COALESCE(d_sub.sort_order, 0) ASC')
            ->orderByRaw("COALESCE(NULLIF(d_sub.department_name, ''), '') ASC")
            ->orderByRaw('CASE WHEN p_order.position_rank IS NULL THEN 1 ELSE 0 END ASC')
            ->orderByRaw('p_order.position_rank ASC')
            ->orderByRaw("COALESCE(NULLIF(p_order.position_name_km, ''), NULLIF(p_order.position_name, ''), '') ASC")
            ->orderByRaw("COALESCE(NULLIF(employees.last_name, ''), '') ASC")
            ->orderByRaw("COALESCE(NULLIF(employees.first_name, ''), '') ASC")
            ->orderBy('employees.id', 'ASC')
            ->get();

        $employees->each(function ($employee) {
            $employee->setAttribute('display_unit_path', $this->resolveEmployeeDisplayUnitPath($employee));
        });

        $fileName = 'employee_list_official_' . date('Ymd_His') . '.xlsx';

        return Excel::download(
            new EmployeeListOfficialExport($employees, $this->buildEmployeeExportMeta()),
            $fileName
        );
    }

    /**
