    public function storeStatusTransition(Request $request, $id)
    {
        $allowedActiveStatuses = $this->activeMasterWorkStatusNames();

        $validated = $request->validate([
            'to_work_status_name' => ['required', 'string', 'max:191', Rule::in($allowedActiveStatuses)],
            'effective_date' => 'required|date',
            'document_reference' => 'nullable|string|max:191',
            'document_date' => 'nullable|date',
            'note' => 'nullable|string',
            'transition_type' => 'nullable|string|max:60',
        ]);

        $transitionType = trim((string) ($validated['transition_type'] ?? 'status_change'));
        $documentReference = trim((string) ($validated['document_reference'] ?? ''));
        $note = trim((string) ($validated['note'] ?? ''));
        $statusGroup = $this->resolveTransitionGroupForStatusName((string) $validated['to_work_status_name']);

