                ->withInput();
        }

        DB::beginTransaction();
        try {
            $employee = $this->findManagedEmployeeOrFail($id);

            $this->statusTransitionService()->apply($employee, [
                'to_work_status_name' => $validated['to_work_status_name'],
                'effective_date' => $validated['effective_date'] ?? null,
                'document_reference' => $validated['document_reference'] ?? null,
                'document_date' => $validated['document_date'] ?? null,
                'note' => $validated['note'] ?? null,
                'transition_type' => $validated['transition_type'] ?? 'status_change',
                'transition_source' => 'manual_status_transition',
            ]);

            DB::commit();
            Toastr::success('Status transition saved successfully :)', 'Success');
            return redirect()->back();
        } catch (\Throwable $exception) {
            DB::rollBack();
            Toastr::error('Something went wrong :)', 'Errors');
            return redirect()->back()->withInput();
        }
