    /**
     * Remove the specified resource from storage.
     * @param int $id
     * @return Renderable
     */
    public function destroy($id)
    {
        DB::beginTransaction();
        try {
            $employee = $this->findManagedEmployeeOrFail($id, ['user', 'subCode' => function ($query) {
                $query->where('acc_subtype_id', 1);
            }]);

            $linkedUser = $employee->user;
            if ($linkedUser && (int) ($linkedUser->user_type_id ?? 0) === 2) {
                $linkedUser->is_active = false;
                $linkedUser->save();
            }

            $employee->delete();

            DB::commit();
            return response()->json(['success' => 'success']);
        } catch (\Exception $e) {
            DB::rollback();
            return redirect()->back();
        }
    }

    /**
     * Download employee PDF.
     * @param int $id
     * @return Renderable
     */
    public function download($id)
    {
        $employee = $this->findManagedEmployeeOrFail($id);
        $pdfData = $this->employeeProfilePdfData($employee);
        $fileName = 'employee-info-' . ($employee->employee_id ?: $employee->id) . '.pdf';

        $wordPdfDownload = $this->renderEmployeeProfilePdfFromWordTemplate($pdfData, $fileName, false);
        if ($wordPdfDownload) {
            return $wordPdfDownload;
        }

        $chromePdfDownload = $this->renderEmployeeProfilePdfByHeadlessBrowser($pdfData, $fileName, false);
        if ($chromePdfDownload) {
            return $chromePdfDownload;
        }

        $pdf = Pdf::loadView('humanresource::employee.employee_pdf', $pdfData)
            ->setPaper('A4', 'portrait')
            ->setOption('defaultFont', 'khmerbody')
            ->setOption('isHtml5ParserEnabled', true)
            ->setOption('isRemoteEnabled', true);

        return $pdf->download($fileName);
    }

    /**
     * Print employee profile PDF in browser.
     */
    public function printProfile($id)
    {
        $employee = $this->findManagedEmployeeOrFail($id);
        $pdfData = $this->employeeProfilePdfData($employee);
        $fileName = 'employee-profile-' . ($employee->employee_id ?: $employee->id) . '.pdf';

        $wordPdfStream = $this->renderEmployeeProfilePdfFromWordTemplate($pdfData, $fileName, true);
        if ($wordPdfStream) {
            return $wordPdfStream;
        }

        $chromePdfStream = $this->renderEmployeeProfilePdfByHeadlessBrowser($pdfData, $fileName, true);
        if ($chromePdfStream) {
            return $chromePdfStream;
        }

        $pdf = Pdf::loadView('humanresource::employee.employee_pdf', $pdfData)
            ->setPaper('A4', 'portrait')
            ->setOption('defaultFont', 'khmerbody')
            ->setOption('isHtml5ParserEnabled', true)
            ->setOption('isRemoteEnabled', true);

        return $pdf->stream($fileName);
    }

    /**
     * Print detailed employee profile PDF in browser.
     */
    public function printDetailProfile($id)
    {
        $employee = $this->findManagedEmployeeOrFail($id, [
            'department',
            'position',
            'gender',
            'marital_status',
            'employee_type',
            'profileExtra',
            'familyMembers',
            'educationHistories',
            'foreignLanguages',
            'bankAccounts',
            'workHistories',
            'serviceHistories',
            'legalRecords',
        ]);

        $pdfData = $this->employeeProfilePdfData($employee);
        $fileName = 'employee-detail-' . ($employee->employee_id ?: $employee->id) . '.pdf';

        $viewData = array_merge($pdfData, [
            'application' => Application::query()->first(),
            'family_members' => $employee->familyMembers
                ->sortBy('id')
                ->values(),
            'education_histories' => $employee->educationHistories
                ->sortByDesc(function ($row) {
                    return $row->end_date ?: $row->start_date ?: $row->id;
                })
                ->values(),
            'foreign_languages' => $employee->foreignLanguages
                ->sortBy('id')
                ->values(),
            'bank_accounts' => $employee->bankAccounts
                ->sortBy('id')
                ->values(),
            'work_histories' => $employee->workHistories
                ->sortByDesc(function ($row) {
                    return $row->start_date ?: $row->id;
                })
                ->values(),
            'service_histories' => $employee->serviceHistories
                ->sortByDesc(function ($row) {
                    return $row->event_date ?: $row->created_at;
                })
                ->values(),
            'legal_records' => $employee->legalRecords
                ->sortByDesc(function ($row) {
                    return $row->document_date ?: $row->effective_date ?: $row->created_at;
                })
                ->values(),
        ]);

        $chromePdfStream = $this->renderEmployeeProfilePdfByHeadlessBrowser(
            $viewData,
            $fileName,
            true,
            'humanresource::employee.employee_detail_pdf'
        );
        if ($chromePdfStream) {
            return $chromePdfStream;
        }

        $pdf = Pdf::loadView('humanresource::employee.employee_detail_pdf', $viewData)
            ->setPaper('A4', 'portrait')
            ->setOption('defaultFont', 'khmerbody')
            ->setOption('isHtml5ParserEnabled', true)
            ->setOption('isRemoteEnabled', true);

        return $pdf->stream($fileName);
    }

    protected function renderEmployeeProfilePdfFromWordTemplate(array $viewData, string $fileName, bool $inline = false): ?BinaryFileResponse
    {
        $templatePath = $this->resolveEmployeeProfileWordTemplatePath();
        if (!$templatePath) {
            return null;
        }

        $officePath = $this->resolveOfficeConverterPath();
        if (!$officePath) {
            return null;
        }

        $profile = (array) data_get($viewData, 'profile', []);
        $placeholders = $this->employeeProfileWordTemplateVariables($profile);

        $tmpDir = storage_path('app/tmp/employee-profile-docx');
        if (!is_dir($tmpDir)) {
            @mkdir($tmpDir, 0777, true);
        }

        $token = bin2hex(random_bytes(8));
        $docxPath = $tmpDir . DIRECTORY_SEPARATOR . 'employee_profile_' . $token . '.docx';
        $pdfPath = $tmpDir . DIRECTORY_SEPARATOR . 'employee_profile_' . $token . '.pdf';

        try {
            if (!$this->fillWordTemplateDocx($templatePath, $docxPath, $placeholders)) {
                return null;
            }

            $process = new Process([
                $officePath,
                '--headless',
                '--norestore',
                '--nolockcheck',
                '--convert-to',
                'pdf:writer_pdf_Export',
                '--outdir',
                $tmpDir,
                $docxPath,
            ]);
            $process->setTimeout(120);
            $process->run();

            $generatedPdfPath = $tmpDir . DIRECTORY_SEPARATOR . pathinfo($docxPath, PATHINFO_FILENAME) . '.pdf';
            if ($generatedPdfPath !== $pdfPath && is_file($generatedPdfPath)) {
                @rename($generatedPdfPath, $pdfPath);
            }

            if (!$process->isSuccessful() || !is_file($pdfPath) || filesize($pdfPath) === 0) {
                Log::warning('Word template employee profile PDF export failed. Falling back to browser/DomPDF.', [
                    'template' => $templatePath,
                    'office' => $officePath,
                    'error' => $process->getErrorOutput(),
                ]);
                @unlink($pdfPath);
                return null;
            }

            if ($inline) {
                return response()
                    ->file($pdfPath, [
                        'Content-Type' => 'application/pdf',
                        'Content-Disposition' => 'inline; filename="' . $fileName . '"',
                    ])
                    ->deleteFileAfterSend(true);
            }

            return response()
                ->download($pdfPath, $fileName, ['Content-Type' => 'application/pdf'])
                ->deleteFileAfterSend(true);
        } catch (\Throwable $exception) {
            Log::warning('Word template employee profile PDF export exception. Falling back to browser/DomPDF.', [
                'template' => $templatePath,
                'office' => $officePath,
                'error' => $exception->getMessage(),
            ]);

            @unlink($pdfPath);
            return null;
        } finally {
            @unlink($docxPath);
        }
    }

    protected function resolveEmployeeProfileWordTemplatePath(): ?string
    {
        $envPath = trim((string) env('EMPLOYEE_PROFILE_WORD_TEMPLATE', ''));
        if ($envPath !== '' && is_file($envPath)) {
            return $envPath;
        }

        $candidates = [
            storage_path('app/public/templates/employee-profile-template.docx'),
            storage_path('app/templates/employee-profile-template.docx'),
            base_path('templates/employee-profile-template.docx'),
        ];

        $dynamicGlobs = [
            storage_path('app/public/templates/*.docx'),
            storage_path('app/templates/*.docx'),
        ];

        foreach ($dynamicGlobs as $pattern) {
            $matches = glob($pattern) ?: [];
            foreach ($matches as $match) {
                $candidates[] = $match;
            }
        }

        foreach ($candidates as $candidate) {
            if (is_file($candidate)) {
                return $candidate;
            }
        }

        return null;
    }

    protected function resolveOfficeConverterPath(): ?string
    {
        $envPath = trim((string) env('PDF_OFFICE_PATH', env('SOFFICE_PATH', '')));
        if ($this->isValidOfficeCommand($envPath)) {
            return $envPath;
        }

        $candidates = [
            'C:/Program Files/LibreOffice/program/soffice.exe',
            'C:/Program Files/LibreOffice/program/soffice.com',
            'C:/Program Files (x86)/LibreOffice/program/soffice.exe',
            'C:/Program Files (x86)/LibreOffice/program/soffice.com',
            '/usr/bin/libreoffice',
            '/usr/bin/soffice',
            '/snap/bin/libreoffice',
            '/Applications/LibreOffice.app/Contents/MacOS/soffice',
            'soffice',
            'libreoffice',
        ];

        foreach ($candidates as $candidate) {
            if ($this->isValidOfficeCommand($candidate)) {
                return $candidate;
            }
        }

        return null;
    }

    protected function isValidOfficeCommand(string $command): bool
    {
        if ($command === '') {
            return false;
        }

        $normalized = str_replace('\\', '/', $command);
        $looksLikePath = str_contains($normalized, '/') || (bool) preg_match('/^[A-Za-z]:\//', $normalized);

        if ($looksLikePath) {
            return is_file($command);
        }

        return true;
    }

    protected function employeeProfileWordTemplateVariables(array $profile): array
    {
        $khmerDigitMap = [
