            '2' => json_decode('"\u17e2"') ?: '2',
            '3' => json_decode('"\u17e3"') ?: '3',
            '4' => json_decode('"\u17e4"') ?: '4',
            '5' => json_decode('"\u17e5"') ?: '5',
            '6' => json_decode('"\u17e6"') ?: '6',
            '7' => json_decode('"\u17e7"') ?: '7',
            '8' => json_decode('"\u17e8"') ?: '8',
            '9' => json_decode('"\u17e9"') ?: '9',
        ];

        $toKhmerDigits = static function ($value) use ($khmerDigitMap): string {
            return strtr((string) $value, $khmerDigitMap);
        };

        $toKhmerDate = static function ($value) use ($toKhmerDigits): string {
            if (blank($value)) {
                return '';
            }

            try {
                $date = \Carbon\Carbon::parse($value);
                return $toKhmerDigits($date->format('d-m-Y'));
            } catch (\Throwable $exception) {
                return $toKhmerDigits((string) $value);
            }
        };

        $khmerOnly = static function ($value) use ($toKhmerDigits): string {
            $text = trim((string) $value);
            if ($text === '') {
                return '';
            }

            $text = $toKhmerDigits($text);
            $text = preg_replace('/[^\x{1780}-\x{17FF}\x{19E0}-\x{19FF}\x{200c}\x{200d}\s\-\/\(\)\.,]/u', '', $text) ?? '';

            return trim($text);
        };

        $toArabicDigits = static function ($value): string {
            return strtr((string) $value, [
                (json_decode('"\u17e0"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â ') => '0',
                (json_decode('"\u17e1"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¡') => '1',
                (json_decode('"\u17e2"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¢') => '2',
                (json_decode('"\u17e3"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â£') => '3',
                (json_decode('"\u17e4"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¤') => '4',
                (json_decode('"\u17e5"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¥') => '5',
                (json_decode('"\u17e6"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¦') => '6',
                (json_decode('"\u17e7"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â§') => '7',
                (json_decode('"\u17e8"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â¨') => '8',
                (json_decode('"\u17e9"') ?: 'ÃƒÆ’Ã‚Â¡Ãƒâ€¦Ã‚Â¸Ãƒâ€šÃ‚Â©') => '9',
            ]);
        };

        $toInt = static function ($value) use ($toArabicDigits): int {
            $raw = $toArabicDigits($value);
            $digitsOnly = preg_replace('/[^0-9]/', '', $raw) ?? '';
            if ($digitsOnly === '') {
                return 0;
            }

            return (int) $digitsOnly;
        };

        $ageFromDate = static function ($value) use ($toKhmerDigits): string {
            if (blank($value)) {
                return json_decode('"\u17e0"') ?: '0';
            }

            try {
                $age = \Carbon\Carbon::parse($value)->age;
                $age = is_numeric($age) ? max((int) $age, 0) : 0;

                return $toKhmerDigits((string) $age);
            } catch (\Throwable $exception) {
                return json_decode('"\u17e0"') ?: '0';
            }
        };

        // Re-define Khmer date text formatters with stable Unicode-safe literals.
        $khmerLunarDateText = static function (): string {
            $fallback = (json_decode('"\u1790\u17d2\u1784\u17c3........ \u1781\u17c2........ \u1786\u17d2\u1793\u17b6\u17c6........ \u1796\u179f........"') ?: '');

            try {
                $khmerDate = new \PPhatDev\LunarDate\KhmerDate(\Carbon\Carbon::today()->toDateString());
                $text = trim((string) $khmerDate->toLunarDate());
                $prefix = json_decode('"/^\s*\u178f\u17d2\u179a\u17bc\u179c\s*\u1793\u17b9\u1784\s*/u"');
                if (is_string($prefix) && $prefix !== '') {
                    $text = preg_replace($prefix, '', $text) ?: $text;
                }

                $replaceFrom = [
                    json_decode('"\u1796\u17bb\u1791\u17d2\u1792\u179f\u1780\u179a\u17b6\u1787"') ?: '',
                    json_decode('"\u1796.\u179f."') ?: '',
                    json_decode('"\u1796.\u179f"') ?: '',
                ];
                $replaceFrom = array_values(array_filter($replaceFrom, static fn($v) => is_string($v) && $v !== ''));
                $replaceTo = (json_decode('"\u1796\u179f"') ?: '');
                if (!empty($replaceFrom) && $replaceTo !== '') {
                    $text = str_replace($replaceFrom, $replaceTo, $text);
                }

                return $text !== '' ? $text : $fallback;
            } catch (\Throwable $exception) {
                return $fallback;
