        };

        $khmerSolarDateText = static function (?string $location = null) use ($toKhmerDigits): string {
            $months = [
                1 => json_decode('"\u1798\u1780\u179a\u17b6"') ?: '',
                2 => json_decode('"\u1780\u17bb\u1798\u17d2\u1797\u17c8"') ?: '',
                3 => json_decode('"\u1798\u17b8\u1793\u17b6"') ?: '',
