        $resolveGenderKh = static function ($value, $genderId = null): string {
            $raw = trim((string) $value);
            $norm = mb_strtolower($raw, 'UTF-8');

            if (
                str_contains($norm, (json_decode('"\u1794\u17d2\u179a\u17bb\u179f"') ?: ''))
