    protected function escapeWordTemplateValue(string $value): string
    {
        $clean = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/u', '', $value) ?? '';

        return str_replace(["\r\n", "\r", "\n"], ' ', $clean);
    }

    protected function escapeWordXmlValue(string $value): string
    {
        return htmlspecialchars($this->escapeWordTemplateValue($value), ENT_QUOTES | ENT_XML1, 'UTF-8');
    }

    protected function fillWordTemplateDocx(string $templatePath, string $outputPath, array $placeholders): bool
    {
        if (!is_file($templatePath)) {
            return false;
        }

        if (@copy($templatePath, $outputPath) === false) {
            return false;
        }

        $zip = new \ZipArchive();
        if ($zip->open($outputPath) !== true) {
            @unlink($outputPath);
            return false;
        }

        try {
            for ($i = 0; $i < $zip->numFiles; $i++) {
                $entryName = $zip->getNameIndex($i);
                if (!is_string($entryName) || !str_starts_with($entryName, 'word/') || !str_ends_with($entryName, '.xml')) {
                    continue;
                }

                $xml = $zip->getFromIndex($i);
                if (!is_string($xml) || $xml === '') {
                    continue;
                }

                // Word often injects proofing markers and splits placeholder text across runs.
                // Remove lightweight proofing tags first so token matching is more reliable.
                $xml = preg_replace('/<w:proofErr[^>]*\/>/u', '', $xml) ?? $xml;

                foreach ($placeholders as $key => $value) {
                    $token = '${' . $key . '}';
                    $xmlValue = $this->escapeWordXmlValue((string) $value);

                    // Fast path for normal (non-split) placeholders.
                    if (str_contains($xml, $token)) {
                        $xml = str_replace($token, $xmlValue, $xml);
                        continue;
                    }

                    // Fallback for split tokens such as `${` + `full_name` + `}` across multiple runs.
                    $splitTokenPattern = $this->buildSplitWordTokenPattern($token);
                    if ($splitTokenPattern !== null) {
                        $xml = preg_replace($splitTokenPattern, $xmlValue, $xml) ?? $xml;
                    }
                }

                $zip->addFromString($entryName, $xml);
            }
        } catch (\Throwable $exception) {
            Log::warning('Word template replacement failed.', [
                'template' => $templatePath,
                'error' => $exception->getMessage(),
            ]);
            $zip->close();
            @unlink($outputPath);
            return false;
        }

        $zip->close();
        return true;
    }

    protected function buildSplitWordTokenPattern(string $token): ?string
    {
        $chars = preg_split('//u', $token, -1, PREG_SPLIT_NO_EMPTY);
        if (!is_array($chars) || $chars === []) {
            return null;
        }

        $parts = array_map(static function (string $char): string {
            return preg_quote($char, '/');
        }, $chars);

        // Allow XML tags to appear between any two token characters.
        return '/' . implode('(?:<[^>]+>)*', $parts) . '/u';
    }

    protected function renderEmployeeProfilePdfByHeadlessBrowser(
        array $viewData,
        string $fileName,
        bool $inline = false,
        string $viewName = 'humanresource::employee.employee_pdf'
    ): ?BinaryFileResponse
    {
        $browserPath = $this->resolvePdfBrowserPath();
        if (!$browserPath) {
            return null;
        }

        $tmpDir = storage_path('app/tmp/employee-profile-pdf');
        if (!is_dir($tmpDir)) {
            @mkdir($tmpDir, 0777, true);
        }

        $token = bin2hex(random_bytes(8));
        $htmlPath = $tmpDir . DIRECTORY_SEPARATOR . 'employee_profile_' . $token . '.html';
        $pdfPath = $tmpDir . DIRECTORY_SEPARATOR . 'employee_profile_' . $token . '.pdf';

        try {
            $html = view($viewName, $viewData)->render();
            if (@file_put_contents($htmlPath, $html) === false) {
                return null;
            }

            $process = new Process([
                $browserPath,
                '--headless',
                '--disable-gpu',
                '--no-sandbox',
                '--disable-dev-shm-usage',
                '--allow-file-access-from-files',
                '--no-pdf-header-footer',
                '--print-to-pdf=' . $pdfPath,
                '--print-to-pdf-no-header',
                $htmlPath,
            ]);

            $process->setTimeout(90);
            $process->run();

            if (!$process->isSuccessful() || !is_file($pdfPath) || filesize($pdfPath) === 0) {
                Log::warning('Headless browser employee profile PDF export failed. Falling back to DomPDF.', [
                    'browser' => $browserPath,
                    'error' => $process->getErrorOutput(),
                ]);
                @unlink($pdfPath);
                return null;
            }

            if ($inline) {
                return response()
                    ->file($pdfPath, [
                        'Content-Type' => 'application/pdf',
                        'Content-Disposition' => 'inline; filename="' . $fileName . '"',
                    ])
                    ->deleteFileAfterSend(true);
            }

            return response()
                ->download($pdfPath, $fileName, ['Content-Type' => 'application/pdf'])
                ->deleteFileAfterSend(true);
        } catch (\Throwable $exception) {
            Log::warning('Headless browser employee profile PDF export exception. Falling back to DomPDF.', [
                'browser' => $browserPath,
                'error' => $exception->getMessage(),
            ]);

            @unlink($pdfPath);
            return null;
        } finally {
            @unlink($htmlPath);
        }
    }

    protected function resolvePdfBrowserPath(): ?string
    {
        $envPath = trim((string) env('PDF_BROWSER_PATH', ''));
        if ($this->isValidBrowserCommand($envPath)) {
            return $envPath;
        }

        $candidates = [
            'C:/Program Files/Google/Chrome/Application/chrome.exe',
            'C:/Program Files (x86)/Google/Chrome/Application/chrome.exe',
            'C:/Program Files/Microsoft/Edge/Application/msedge.exe',
            'C:/Program Files (x86)/Microsoft/Edge/Application/msedge.exe',
            '/usr/bin/google-chrome',
            '/usr/bin/chromium-browser',
            '/usr/bin/chromium',
            '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
            '/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge',
            'chrome',
            'google-chrome',
            'chromium-browser',
            'chromium',
            'msedge',
        ];

        foreach ($candidates as $candidate) {
            if ($this->isValidBrowserCommand($candidate)) {
                return $candidate;
            }
        }

        return null;
    }

    protected function isValidBrowserCommand(string $command): bool
    {
        if ($command === '') {
            return false;
        }

        $normalized = str_replace('\\', '/', $command);
        $looksLikePath = str_contains($normalized, '/') || (bool) preg_match('/^[A-Za-z]:\//', $normalized);

        if ($looksLikePath) {
            return is_file($command);
        }

        return true;
    }

