        $normalizeDegreeLevelKey = static function (?string $value) use ($degreeLevelOrder, $degreeLevelKhLabel): string {
            $raw = trim((string) $value);
            if ($raw === '') {
                return '';
            }

            if (array_key_exists($raw, $degreeLevelOrder)) {
                return $raw;
            }

            $needle = mb_strtolower($raw, 'UTF-8');
            foreach ($degreeLevelKhLabel as $key => $label) {
                if ($needle === mb_strtolower($label, 'UTF-8')) {
                    return $key;
                }
            }

            return '';
        };

        $highestGeneralEducationKey = '';
        $highestGeneralEducationLabel = '';
        $highestGeneralEducationRank = 0;
        foreach ($educationHistories as $educationRow) {
            $degreeKey = $normalizeDegreeLevelKey((string) ($educationRow->degree_level ?? ''));
            if ($degreeKey === '') {
                continue;
            }

            $rank = (int) ($degreeLevelOrder[$degreeKey] ?? 0);
            if ($rank <= $highestGeneralEducationRank) {
                continue;
            }

            $highestGeneralEducationRank = $rank;
            $highestGeneralEducationKey = $degreeKey;
            $highestGeneralEducationLabel = (string) ($degreeLevelKhLabel[$degreeKey] ?? $educationRow->degree_level ?? '');
        }

                $nationalEducationFromHighestGeneralKnowledge = match ($highestGeneralEducationKey) {
            'primary_certificate' => (json_decode('"\u1794\u178b\u1798"') ?: ''),
            'lower_secondary_diploma' => (json_decode('"\u1794\u178b\u1798\u1797\u17bc\u1798\u17b7"') ?: ''),
            'upper_secondary_diploma',
            'vocational_certificate',
            'technical_diploma',
            'associate_degree',
            'higher_diploma',
            'bachelor_degree',
            'professional_bachelor_degree',
            'postgraduate_certificate',
            'postgraduate_diploma',
            'master_degree',
            'specialist_degree',
            'doctorate_degree',
            'postdoctorate_degree' => (json_decode('"\u1791\u17bb\u178f\u17b7\u1799\u1797\u17bc\u1798\u17b7"') ?: ''),
            default => '',
        };

        $foreignLanguageNames = EmployeeForeignLanguage::query()
            ->where('employee_id', $employee->id)
            ->orderBy('id')
            ->pluck('language_name')
            ->map(static function ($name) {
                return trim((string) $name);
            })
            ->filter(static function ($name) {
                return $name !== '';
            })
            ->unique()
            ->values();
        $foreignLanguageSummary = $foreignLanguageNames->implode(', ');

