        $nodeKhmerLabel = static function (?array $node) use ($safeText): string {
            if (!is_array($node)) {
                return '';
            }

            return $safeText($node['khmer'] ?? $node['name'] ?? $node['latin'] ?? '');
        };

        $loadGazetteerIndexes = static function () use ($safeText, $nodeKhmerLabel): array {
            static $cache = null;
            if ($cache !== null) {
                return $cache;
            }

            $cache = [
                'province' => [],
                'district' => [],
                'commune' => [],
                'village' => [],
            ];

            $path = public_path('module-assets/HumanResource/data/cambodia_gazetteer.json');
            if (!is_file($path)) {
                return $cache;
            }

            $raw = @file_get_contents($path);
            if (!is_string($raw) || trim($raw) === '') {
                return $cache;
            }

            $rows = json_decode($raw, true);
            if (!is_array($rows)) {
                return $cache;
            }

            foreach ($rows as $provinceNode) {
                if (!is_array($provinceNode)) {
                    continue;
                }

                $provinceCode = $safeText($provinceNode['code'] ?? '');
                if ($provinceCode === '') {
                    continue;
                }

                $cache['province'][$provinceCode] = $nodeKhmerLabel($provinceNode);
                $districtNodes = is_array($provinceNode['districts'] ?? null) ? $provinceNode['districts'] : [];

                foreach ($districtNodes as $districtNode) {
                    if (!is_array($districtNode)) {
                        continue;
                    }

                    $districtCode = $safeText($districtNode['code'] ?? '');
                    if ($districtCode === '') {
                        continue;
                    }

                    $cache['district'][$districtCode] = [
                        'name' => $nodeKhmerLabel($districtNode),
                        'province_code' => $provinceCode,
                    ];

                    $communeNodes = is_array($districtNode['communes'] ?? null) ? $districtNode['communes'] : [];
                    foreach ($communeNodes as $communeNode) {
                        if (!is_array($communeNode)) {
                            continue;
                        }

                        $communeCode = $safeText($communeNode['code'] ?? '');
                        if ($communeCode === '') {
                            continue;
                        }

                        $cache['commune'][$communeCode] = [
                            'name' => $nodeKhmerLabel($communeNode),
                            'district_code' => $districtCode,
                            'province_code' => $provinceCode,
                        ];

                        $villageNodes = is_array($communeNode['villages'] ?? null) ? $communeNode['villages'] : [];
                        foreach ($villageNodes as $villageNode) {
                            if (!is_array($villageNode)) {
                                continue;
                            }

                            $villageCode = $safeText($villageNode['code'] ?? '');
                            if ($villageCode === '') {
                                continue;
                            }

                            $cache['village'][$villageCode] = [
                                'name' => $nodeKhmerLabel($villageNode),
                                'commune_code' => $communeCode,
                                'district_code' => $districtCode,
                                'province_code' => $provinceCode,
                            ];
                        }
                    }
                }
            }

            return $cache;
        };

        $resolveGazetteerNames = static function (
