                    $communeCode = substr($villageCode, 0, 6);
                }
                if ($districtCode === '' && strlen($villageCode) >= 4) {
                    $districtCode = substr($villageCode, 0, 4);
                }
                if ($provinceCode === '' && strlen($villageCode) >= 2) {
