            $villageMeta = ($villageCode !== '' && isset($indexes['village'][$villageCode]))
                ? $indexes['village'][$villageCode]
                : null;
            if (is_array($villageMeta)) {
                $communeCode = $communeCode !== '' ? $communeCode : $safeText($villageMeta['commune_code'] ?? '');
                $districtCode = $districtCode !== '' ? $districtCode : $safeText($villageMeta['district_code'] ?? '');
                $provinceCode = $provinceCode !== '' ? $provinceCode : $safeText($villageMeta['province_code'] ?? '');
            }

            $communeMeta = ($communeCode !== '' && isset($indexes['commune'][$communeCode]))
                ? $indexes['commune'][$communeCode]
                : null;
            if (is_array($communeMeta)) {
                $districtCode = $districtCode !== '' ? $districtCode : $safeText($communeMeta['district_code'] ?? '');
                $provinceCode = $provinceCode !== '' ? $provinceCode : $safeText($communeMeta['province_code'] ?? '');
            }

            $districtMeta = ($districtCode !== '' && isset($indexes['district'][$districtCode]))
                ? $indexes['district'][$districtCode]
                : null;
            if (is_array($districtMeta)) {
                $provinceCode = $provinceCode !== '' ? $provinceCode : $safeText($districtMeta['province_code'] ?? '');
            }

            return [
                'province' => $safeText($indexes['province'][$provinceCode] ?? ''),
                'district' => $safeText(is_array($districtMeta) ? ($districtMeta['name'] ?? '') : ''),
                'commune' => $safeText(is_array($communeMeta) ? ($communeMeta['name'] ?? '') : ''),
