            'father_ethnicity' => (string) (data_get($employee, 'father_ethnicity') ?: data_get($fatherMember, 'ethnicity') ?: ''),
            'father_dob' => data_get($employee, 'father_dob') ?: data_get($fatherMember, 'date_of_birth'),
            'father_job' => (string) (data_get($employee, 'father_job') ?: data_get($fatherMember, 'occupation') ?: ''),
            'father_address' => (string) $fatherAddressFull,
            'father_address_full' => (string) $fatherAddressFull,
            'father_address_state' => (string) $fatherProvince,
            'father_address_city' => (string) $fatherDistrict,
            'father_address_commune' => (string) $fatherCommune,
            'father_address_village' => (string) $fatherVillage,
            'mother_name' => (string) ($employee->mother_name ?? $familyName($motherMember) ?? ''),
            'mother_nationality' => (string) (data_get($employee, 'mother_nationality') ?: data_get($motherMember, 'nationality') ?: ''),
            'mother_ethnicity' => (string) (data_get($employee, 'mother_ethnicity') ?: data_get($motherMember, 'ethnicity') ?: ''),
            'mother_dob' => data_get($employee, 'mother_dob') ?: data_get($motherMember, 'date_of_birth'),
            'mother_job' => (string) (data_get($employee, 'mother_job') ?: data_get($motherMember, 'occupation') ?: ''),
            'mother_address' => (string) $motherAddressFull,
            'mother_address_full' => (string) $motherAddressFull,
            'mother_address_state' => (string) $motherProvince,
            'mother_address_city' => (string) $motherDistrict,
            'mother_address_commune' => (string) $motherCommune,
            'mother_address_village' => (string) $motherVillage,
            'issue_place' => $issuePlace,
            'issue_day' => $toKhmerDigits($today->format('d')),
            'issue_month' => $toKhmerDigits($today->format('m')),
            'issue_year' => $toKhmerDigits($today->format('Y')),
        ];

        array_walk($profile, static function (&$value) use ($normalizeKh) {
            if (is_string($value)) {
                $value = $normalizeKh($value);
            }
        });

        $rules = SetupRule::where('is_active', true)->with('employee_salary_types', function ($q) use ($employee) {
            return $q->where('employee_id', $employee->id);
        })->get();

        $times = $rules->filter(function ($value) {
            return $value->type == 'time';
        });

        $deductions = $rules->filter(function ($value) use ($employee) {
            return $value->type == 'deduction';
        });

        $allowances = $rules->filter(function ($value) {
            return $value->type == 'allowance';
        });

        return compact('employee', 'bank_info', 'employee_file', 'times', 'deductions', 'allowances', 'academicInfos', 'profile');
    }

