    public function careerManagement($id)
    {
        $employee = $this->findManagedEmployeeOrFail($id, [
            'workHistories' => function ($query) {
                $query->orderByRaw('CASE WHEN start_date IS NULL THEN 1 ELSE 0 END ASC')
                    ->orderByDesc('start_date')
                    ->orderByRaw('CASE WHEN document_date IS NULL THEN 1 ELSE 0 END ASC')
                    ->orderByDesc('document_date')
                    ->orderByDesc('id');
            },
            'incentives',
            'department',
            'sub_department',
            'position',
        ]);

        return view('humanresource::employee.career-management', [
            'employee' => $employee,
            'work_status_options' => $this->workStatusOptions(),
            'return_to_work_status_name' => $this->defaultReturnToWorkStatusName(),
        ]);
    }

    public function careerManagementUpdate(Request $request, $id)
    {
        $allowedWorkStatuses = $this->allMasterWorkStatusNames();

        $request->validate([
            'work_histories' => 'nullable|array',
            'work_histories.*.id' => 'nullable|integer',
            'work_histories.*.work_status_name' => ['nullable', 'string', 'max:191', Rule::in($allowedWorkStatuses)],
            'work_histories.*.start_date' => 'nullable|date',
            'work_histories.*.document_reference' => 'nullable|string|max:191',
            'work_histories.*.document_date' => 'nullable|date',
            'work_histories.*.note' => 'nullable|string',

            'incentives' => 'nullable|array',
            'incentives.*.incentive_date' => 'nullable|date',
            'incentives.*.hierarchy_level' => 'nullable|string|max:191',
            'incentives.*.nationality_type' => 'nullable|string|max:191',
            'incentives.*.incentive_type' => 'nullable|string|max:191',
            'incentives.*.incentive_class' => 'nullable|string|max:191',
            'incentives.*.reason' => 'nullable|string',
        ]);

        DB::beginTransaction();
        try {
            $employee = $this->findManagedEmployeeOrFail($id);
            $this->replaceWorkHistories($employee, (array) $request->input('work_histories', []));
            $this->replaceIncentives($employee, (array) $request->input('incentives', []));
            $this->statusTransitionService()->syncFromLatestWorkHistory($employee, 'career_management_update');

            DB::commit();
            Toastr::success('Career management updated successfully :)', 'Success');
            return redirect()->route('employees.career_management.edit', $employee->id);
        } catch (\Throwable $e) {
            DB::rollBack();
            Toastr::error('Something went wrong :)', 'Errors');
            return redirect()->back()->withInput();
        }
    }

