    protected function scopedEmployeeQuery(?bool $isActive = null)
    {
        $query = Employee::query();

        if (!is_null($isActive)) {
            $query->where('is_active', $isActive);
        }

        $this->applyManagedBranchScope($query, $this->managedBranchIds($this->orgUnitRuleService()));

        return $query;
    }

    protected function findManagedEmployeeOrFail($id, array $relations = []): Employee
    {
        $query = Employee::query();
        if (!empty($relations)) {
            $query->with($relations);
        }

        $idText = trim((string) $id);
        $query->where(function ($q) use ($idText) {
            $q->where('uuid', $idText);
            if (ctype_digit($idText)) {
                $q->orWhere('id', (int) $idText);
            }
        });

        $employee = $query->firstOrFail();
        $this->assertCanManageEmployee($employee);

        return $employee;
    }

    protected function managedBranchIds(OrgUnitRuleService $orgUnitRuleService): ?array
    {
        return app(OrgHierarchyAccessService::class)->managedBranchIds(auth()->user());
    }

    /**
     * Provincial hospital should manage own unit only.
     */
    protected function isOwnOnlyRootUnit(int $departmentId): bool
    {
        $dept = Department::withoutGlobalScopes()
            ->with('unitType:id,code')
            ->select('id', 'unit_type_id')
            ->find($departmentId);

        if (!$dept) {
            return false;
        }

        $unitTypeCode = (string) optional($dept->unitType)->code;
        if ($unitTypeCode !== '') {
            return $unitTypeCode === 'provincial_hospital';
        }

        // Fallback for legacy data where relation/code is unavailable.
        return (int) $dept->unit_type_id === 6;
    }

    protected function applyManagedBranchScope($query, ?array $managedBranchIds): void
    {
        if (!is_array($managedBranchIds)) {
            return;
        }

        if (empty($managedBranchIds)) {
            $query->whereRaw('1=0');
            return;
        }

        $query->where(function ($q) use ($managedBranchIds) {
            $q->whereIn('department_id', $managedBranchIds)
                ->orWhereIn('sub_department_id', $managedBranchIds);
        });
    }

    protected function resolveEmployeeDisplayUnitPath(Employee $employee): string
    {
        $currentId = (int) ($employee->sub_department_id ?: $employee->department_id ?: 0);
        if ($currentId <= 0) {
            return '-';
        }

        $visited = [];
        $chain = [];
        $guard = 0;

        while ($currentId > 0 && $guard < 50) {
            if (isset($visited[$currentId])) {
                break;
            }
            $visited[$currentId] = true;

            $unit = Department::withoutGlobalScopes()
                ->select(['id', 'department_name', 'parent_id'])
                ->find($currentId);

            if (!$unit) {
                break;
            }

            $name = trim((string) ($unit->department_name ?? ''));
            if ($name !== '') {
                $chain[] = $name;
            }

            $currentId = (int) ($unit->parent_id ?? 0);
            $guard++;
        }

        if (empty($chain)) {
            return '-';
        }

        return implode(' | ', array_values(array_unique(array_reverse($chain))));
    }

