        try {
            $app = Application::query()->first();
            if ($app) {
                $meta['admin_text'] = (string) ($app->company_name ?: $meta['admin_text']);
                $meta['unit_text'] = (string) (($app->title ?: $app->site_title ?: $app->company_name) ?: $meta['unit_text']);
