    protected function isSystemAdmin(): bool
    {
        $user = auth()->user();
        return $user && (int) $user->user_type_id === 1;
    }

    protected function currentUserRootUnitId(): ?int
    {
        $user = auth()->user();
        if (!$user) {
            return null;
        }

        $employee = $user->employee()->with('primaryUnitPosting')->first();
        if (!$employee) {
            return null;
        }

        $rootUnitId = $this->employeeAssignedUnitId($employee);
        if ($rootUnitId) {
            return $rootUnitId;
        }

        $postedUnitId = (int) optional($employee->primaryUnitPosting)->department_id;
        return $postedUnitId > 0 ? $postedUnitId : null;
    }

    protected function employeeAssignedUnitId(Employee $employee): ?int
    {
        $unitId = (int) ($employee->sub_department_id ?: $employee->department_id);
        if ($unitId > 0) {
            return $unitId;
        }

        $postedUnitId = (int) optional($employee->primaryUnitPosting)->department_id;
        return $postedUnitId > 0 ? $postedUnitId : null;
    }

    protected function filterHierarchyTreeByAllowedIds(array $nodes, array $allowedIds): array
    {
        $allowedMap = [];
        foreach ($allowedIds as $id) {
            $allowedMap[(int) $id] = true;
        }

        return $this->filterHierarchyTreeNodes($nodes, $allowedMap);
    }

    protected function filterHierarchyTreeNodes(array $nodes, array $allowedMap): array
    {
        $result = [];

        foreach ($nodes as $node) {
            $children = $this->filterHierarchyTreeNodes((array) ($node['children'] ?? []), $allowedMap);
            $nodeId = (int) ($node['id'] ?? 0);

            if (isset($allowedMap[$nodeId])) {
                $node['children'] = $children;
                $result[] = $node;
                continue;
            }

            if (!empty($children)) {
                foreach ($children as $childNode) {
                    $result[] = $childNode;
                }
            }
        }

        return $result;
    }

    protected function normalizedVaccinationRowsFromRequest(Request $request): array
    {
        $rows = (array) $request->input('vaccination_records', []);
        $normalized = $this->normalizedVaccinationRows($rows);

        if (!empty($normalized)) {
            return $normalized;
        }

        $fallbackRow = [
            'vaccine_name' => $request->input('vaccine_name'),
            'vaccine_protection' => $request->input('vaccine_protection'),
            'vaccination_date' => $request->input('vaccination_date'),
            'vaccination_place' => $request->input('vaccination_place'),
        ];

        return $this->normalizedVaccinationRows([$fallbackRow]);
    }

    protected function normalizedVaccinationRows(array $rows): array
    {
        $normalized = [];

        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }

            if (!$this->rowHasAnyValue($row, ['vaccine_name', 'vaccine_protection', 'vaccination_date', 'vaccination_place'])) {
                continue;
            }

            $normalized[] = [
                'vaccine_name' => $this->strOrNull($row['vaccine_name'] ?? null),
                'vaccine_protection' => $this->strOrNull($row['vaccine_protection'] ?? null),
                'vaccination_date' => $row['vaccination_date'] ?? null,
                'vaccination_place' => $this->strOrNull($row['vaccination_place'] ?? null),
            ];
        }

        return $normalized;
    }

    protected function replaceVaccinations(Employee $employee, array $rows): void
    {
        EmployeeVaccination::query()->where('employee_id', $employee->id)->delete();

        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }

            EmployeeVaccination::create([
                'employee_id' => $employee->id,
                'vaccine_name' => $this->strOrNull($row['vaccine_name'] ?? null),
                'vaccine_protection' => $this->strOrNull($row['vaccine_protection'] ?? null),
                'vaccination_date' => $row['vaccination_date'] ?? null,
                'vaccination_place' => $this->strOrNull($row['vaccination_place'] ?? null),
            ]);
        }
    }

    protected function workStatusOptions()
    {
        return EmployeeStatus::query()
            ->where('is_active', true)
            ->orderBy('sort_order')
            ->orderBy('name_en')
            ->get(['name_km', 'name_en'])
            ->map(function ($status) {
                $nameKm = trim((string) ($status->name_km ?? ''));
                $nameEn = trim((string) ($status->name_en ?? ''));

                return $nameKm !== '' ? $nameKm : $nameEn;
            });
    }

    protected function legacyWorkStatusOptionsFromJson()
    {
        $path = storage_path('app/legacy_import/unicode/work_status.json');
        if (!is_file($path)) {
            return collect();
        }

        $json = @file_get_contents($path);
        if (!is_string($json) || trim($json) === '') {
            return collect();
        }

        $rows = json_decode($json, true);
        if (!is_array($rows)) {
            return collect();
        }

        return collect($rows)
            ->map(function ($row) {
                if (!is_array($row)) {
                    return '';
                }

                $khmer = $this->normalizeKhmerText((string) ($row['WorkStatusK'] ?? ''));
                if ($khmer !== '' && preg_match('/\p{Khmer}/u', $khmer)) {
                    return $khmer;
                }

                return trim((string) ($row['WorkStatusE'] ?? ''));
            })
            ->filter()
            ->values();
    }

    protected function normalizeKhmerText(?string $text): string
    {
        $value = trim((string) $text);
        if ($value === '') {
            return '';
        }

        if (preg_match('/\p{Khmer}/u', $value)) {
            return $value;
        }

        $looksMojibake = str_contains($value, 'ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢')
            || str_contains($value, 'ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢')
            || str_contains($value, 'ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦')
            || str_contains($value, 'ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ');

        if (!$looksMojibake) {
            return $value;
        }

        // Try reversing common "UTF-8 interpreted as Windows-1252" corruption.
        $candidate = $value;
        for ($i = 0; $i < 4; $i++) {
            $decoded = @iconv('UTF-8', 'Windows-1252//IGNORE', $candidate);
            if (!is_string($decoded) || $decoded === '') {
                break;
            }

            if (preg_match('/\p{Khmer}/u', $decoded)) {
                return trim($decoded);
            }

            $candidate = $decoded;
        }

        $iconv = @iconv('Windows-1252', 'UTF-8//IGNORE', $value);
        if (is_string($iconv) && $iconv !== '' && preg_match('/\p{Khmer}/u', $iconv)) {
            return trim($iconv);
        }

        return $value;
    }

    protected function replaceWorkHistories(Employee $employee, array $rows): void
    {
        $existingRows = EmployeeWorkHistory::query()
            ->where('employee_id', $employee->id)
            ->get()
            ->keyBy('id');
        $keptIds = [];

        foreach ($rows as $row) {
            $rowId = isset($row['id']) ? (int) $row['id'] : 0;
            if (!$this->rowHasAnyValue($row, ['work_status_name', 'start_date', 'document_reference', 'document_date', 'note'])) {
                continue;
            }

            $payload = [
                'employee_id' => $employee->id,
                'work_status_name' => $this->strOrNull($row['work_status_name'] ?? null),
                'start_date' => $row['start_date'] ?? null,
                'document_reference' => $this->strOrNull($row['document_reference'] ?? null),
                'document_date' => $row['document_date'] ?? null,
                'note' => $this->strOrNull($row['note'] ?? null),
            ];

            if ($rowId > 0 && $existingRows->has($rowId)) {
                $workHistory = $existingRows->get($rowId);
                $workHistory->fill($payload);
                $workHistory->save();
                $keptIds[] = $workHistory->id;
                continue;
            }

            $created = EmployeeWorkHistory::create($payload);
            $keptIds[] = $created->id;
        }

        EmployeeWorkHistory::query()
            ->where('employee_id', $employee->id)
            ->whereNotIn('id', $keptIds ?: [0])
            ->delete();
    }

