    protected function normalizeYearOnlyDate($value): ?string
    {
        $text = trim((string) $value);
        if ($text === '') {
            return null;
        }

        if (preg_match('/^\d{4}$/', $text)) {
            return $text . '-01-01';
        }

        try {
            return \Carbon\Carbon::parse($text)->format('Y-m-d');
        } catch (\Throwable $e) {
            return null;
        }
    }

    protected function normalizeStandardDate($value): ?string
    {
        $text = trim((string) $value);
        if ($text === '') {
            return null;
        }

        foreach (['Y-m-d', 'd/m/Y', 'd-m-Y', 'm/d/Y', 'm-d-Y'] as $format) {
            try {
                return \Carbon\Carbon::createFromFormat($format, $text)->format('Y-m-d');
            } catch (\Throwable $e) {
            }
        }

        try {
            return \Carbon\Carbon::parse($text)->format('Y-m-d');
        } catch (\Throwable $e) {
            return null;
        }
    }

    protected function replaceBankAccounts(Employee $employee, array $rows, Request $request): void
    {
        $existingAccounts = EmployeeBankAccount::query()
            ->where('employee_id', $employee->id)
            ->get();

        foreach ($existingAccounts as $existingAccount) {
            if (!empty($existingAccount->attachment_path)) {
                Storage::disk('public')->delete($existingAccount->attachment_path);
            }
        }

        EmployeeBankAccount::query()->where('employee_id', $employee->id)->delete();

        foreach ($rows as $index => $row) {
            if (!is_array($row)) {
                continue;
            }

            $attachmentFile = $request->file("bank_accounts.$index.attachment");

            if (
                !$this->rowHasAnyValue($row, ['account_name', 'account_number', 'bank_name']) &&
                !$attachmentFile
            ) {
                continue;
            }

            $payload = [
                'employee_id' => $employee->id,
                'account_name' => $this->strOrNull($row['account_name'] ?? null),
                'account_number' => $this->strOrNull($row['account_number'] ?? null),
                'bank_name' => $this->strOrNull($row['bank_name'] ?? null),
            ];

            if ($attachmentFile) {
                $filename = time() . rand(10, 1000) . '.' . $attachmentFile->extension();
                $path = $attachmentFile->storeAs('employee/bank-accounts', $filename, 'public');
                $payload['attachment_name'] = $filename;
                $payload['attachment_path'] = $path;
            }

            EmployeeBankAccount::create($payload);
        }
    }

