    protected function syncCurrentStatusFromLatestWorkHistory(Employee $employee): ?array
    {
        $latest = $this->latestWorkHistoryRecord($employee);
        if (!$latest) {
            return null;
        }

        $status = trim((string) $this->normalizeKhmerText((string) $latest->work_status_name));
        if ($status === '') {
            return null;
        }

        $classification = $this->classifyEmploymentStatusFromName($status);

        $before = [
            'work_status_name' => (string) ($employee->work_status_name ?? ''),
            'work_status_id' => $employee->work_status_id,
            'service_state' => (string) ($employee->service_state ?? ''),
            'is_active' => (int) ($employee->is_active ?? 1),
            'is_left' => (int) ($employee->is_left ?? 0),
        ];

        $employee->work_status_name = $status;
        $employee->work_status_id = $classification['work_status_id'] ?? $employee->work_status_id;
        $employee->service_state = $classification['service_state'];
        $employee->is_active = $classification['is_active'] ? 1 : 0;
        $employee->is_left = $classification['is_left'] ? 1 : 0;

        $after = [
            'work_status_name' => (string) ($employee->work_status_name ?? ''),
            'work_status_id' => $employee->work_status_id,
            'service_state' => (string) ($employee->service_state ?? ''),
            'is_active' => (int) ($employee->is_active ?? 1),
            'is_left' => (int) ($employee->is_left ?? 0),
        ];

        if ($before === $after) {
            return null;
        }

        $employee->save();

        return [
            'before' => $before,
            'after' => $after,
            'effective_date' => $latest->start_date ?: $latest->document_date ?: now()->toDateString(),
            'source' => 'latest_work_history',
        ];
    }

    protected function latestWorkHistoryRecord(Employee $employee): ?EmployeeWorkHistory
    {
        return EmployeeWorkHistory::query()
            ->where('employee_id', $employee->id)
            ->whereNotNull('work_status_name')
            ->where('work_status_name', '<>', '')
            ->orderByRaw('CASE WHEN start_date IS NULL THEN 1 ELSE 0 END ASC')
            ->orderByDesc('start_date')
            ->orderByRaw('CASE WHEN document_date IS NULL THEN 1 ELSE 0 END ASC')
            ->orderByDesc('document_date')
            ->orderByDesc('id')
            ->first();
    }

    protected function classifyEmploymentStatusFromName(string $status): array
    {
        $statusName = trim((string) $status);
        $statusKey = $this->normalizeStatusKey($statusName);
        $legacyMeta = $this->legacyWorkStatusMeta();
        $statusId = $statusKey !== '' ? ($legacyMeta['by_key'][$statusKey] ?? null) : null;

        $serviceState = null;

        if ($statusId !== null) {
            $serviceState = $this->serviceStateByLegacyStatusId((int) $statusId);
            if ($serviceState === null) {
                $activeFlag = $legacyMeta['by_id'][(int) $statusId]['active'] ?? null;
                if ($activeFlag === false) {
                    $serviceState = 'inactive';
                }
            }
        }

        if ($serviceState === null) {
            $serviceState = $this->inferServiceStateFromStatusKeywords($statusName);
        }

        return [
            'work_status_id' => $statusId !== null ? (int) $statusId : null,
            'service_state' => $serviceState,
            'is_active' => $serviceState !== 'inactive',
            'is_left' => $serviceState === 'inactive',
        ];
    }

    protected function serviceStateByLegacyStatusId(int $statusId): ?string
    {
        if (in_array($statusId, self::SERVICE_ACTIVE_STATUS_IDS, true)) {
            return 'active';
        }

        if (in_array($statusId, self::SERVICE_SUSPENDED_STATUS_IDS, true)) {
            return 'suspended';
        }

        if (in_array($statusId, self::SERVICE_INACTIVE_STATUS_IDS, true)) {
            return 'inactive';
        }

        return null;
    }

    protected function inferServiceStateFromStatusKeywords(string $status): string
    {
        $value = mb_strtolower(trim((string) $status), 'UTF-8');
        if ($value === '') {
            return 'active';
        }

        $activeKeywords = [
            'active',
            'returned',
            'reinstated',
            'return to work',
            'back to work',
            'ážŸáž€áž˜áŸ’áž˜',
            'áž…áž¼áž›áž”áŸ†áž–áŸáž‰áž€áž¶ážšáž„áž¶ážšážœáž·áž‰',
            'ážáŸ’ážšáž¡áž”áŸ‹áž…áž¼áž›áž’áŸ’ážœáž¾áž€áž¶ážš',
        ];

        if ($this->statusContainsAny($value, $activeKeywords)) {
            return 'active';
        }

        $inactiveKeywords = [
            'retired',
            'retire',
            'deceased',
            'dead',
            'death',
            'dismissed',
            'terminated',
            'removed',
            'transfer out',
            'resigned',
            'inactive',
            'áž“áž·ážœážáŸ’ážáž“áŸ',
            'ážŸáŸ’áž›áž¶áž”áŸ‹',
            'áž”ážŽáŸ’ážáŸáž‰áž…áŸáž‰',
            'áž•áŸ’áž›áž¶ážŸáŸ‹áž…áŸáž‰',
            'áž¢ážŸáž€áž˜áŸ’áž˜',
        ];

        if ($this->statusContainsAny($value, $inactiveKeywords)) {
            return 'inactive';
        }

        $suspendedKeywords = [
            'without pay',
            'absent without pay',
            'suspend',
            'suspended',
            'study leave',
            'no salary',
            'leave without pay',
            'áž‘áŸ†áž“áŸážšáž‚áŸ’áž˜áž¶áž“áž”áŸ€ážœážáŸ’ážŸ',
            'áž–áŸ’áž™áž½ážšáž€áž¶ážšáž„áž¶ážš',
            'ážˆáž”áŸ‹áž”ážŽáŸ’ážáŸ„áŸ‡áž¢áž¶ážŸáž“áŸ’áž“',
            'ážŸáž˜áŸ’ážšáž¶áž€áž–áŸ’áž™áž¶áž”áž¶áž›áž™áž¼ážš',
        ];

        if ($this->statusContainsAny($value, $suspendedKeywords)) {
            return 'suspended';
        }

        return 'active';
    }

    protected function statusContainsAny(string $value, array $needles): bool
    {
        foreach ($needles as $needle) {
            $needle = mb_strtolower(trim((string) $needle));
            if ($needle === '') {
                continue;
            }

            if (mb_strpos($value, $needle) !== false) {
                return true;
            }
        }

        return false;
    }

    protected function normalizeStatusKey(?string $value): string
    {
        $status = mb_strtolower(trim((string) $value));
        if ($status === '') {
            return '';
        }

        $status = preg_replace('/\s+/u', ' ', $status) ?? $status;
        $status = preg_replace('/[\s\p{P}\p{S}_-]+/u', '', $status) ?? $status;
        return trim($status);
    }

    protected function legacyWorkStatusMeta(): array
    {
        static $cache = null;
        if (is_array($cache)) {
            return $cache;
        }

        $cache = [
            'by_id' => [],
            'by_key' => [],
        ];

        $path = storage_path('app/legacy_import/unicode/work_status.json');
        if (!is_file($path)) {
            return $cache;
        }

        $json = @file_get_contents($path);
        if (!is_string($json) || trim($json) === '') {
            return $cache;
        }

        $rows = json_decode($json, true);
        if (!is_array($rows)) {
            return $cache;
        }

        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }

            $statusId = (int) ($row['WorkStatusID'] ?? 0);
            if ($statusId <= 0) {
                continue;
            }

            $nameEn = trim((string) ($row['WorkStatusE'] ?? ''));
            $nameKm = trim((string) $this->normalizeKhmerText((string) ($row['WorkStatusK'] ?? '')));
            $active = $this->legacyBoolValue($row['Active'] ?? null);

            $cache['by_id'][$statusId] = [
                'name_en' => $nameEn,
                'name_km' => $nameKm,
                'active' => $active,
            ];

            foreach ([$nameEn, $nameKm] as $candidateName) {
                $key = $this->normalizeStatusKey($candidateName);
                if ($key !== '') {
                    $cache['by_key'][$key] = $statusId;
                }
            }
        }

        return $cache;
    }

    protected function legacyBoolValue($value): ?bool
    {
        if ($value === null || $value === '') {
            return null;
        }

        if (is_bool($value)) {
            return $value;
        }

        if (is_numeric($value)) {
            return ((int) $value) !== 0;
        }

        $text = strtolower(trim((string) $value));
        if (in_array($text, ['1', 'true', 'yes', 'y'], true)) {
            return true;
        }

        if (in_array($text, ['0', 'false', 'no', 'n'], true)) {
            return false;
        }

        return null;
    }

    protected function recordServiceStatusChangeEvent(Employee $employee, ?array $syncResult): void
    {
        if (!is_array($syncResult) || empty($syncResult['before']) || empty($syncResult['after'])) {
            return;
        }

        $fromState = $syncResult['before']['service_state'] ?? null;
        $toState = $syncResult['after']['service_state'] ?? null;
        $fromStatus = $syncResult['before']['work_status_name'] ?? null;
        $toStatus = $syncResult['after']['work_status_name'] ?? null;

        EmployeeServiceHistory::create([
            'employee_id' => $employee->id,
            'event_type' => 'status_change',
            'event_date' => $syncResult['effective_date'] ?? now()->toDateString(),
            'title' => 'Employee status changed',
            'details' => 'Auto-updated from latest work history',
            'from_value' => $fromStatus ?: $fromState,
            'to_value' => $toStatus ?: $toState,
            'metadata' => [
                'source' => $syncResult['source'] ?? 'latest_work_history',
                'from' => $syncResult['before'],
                'to' => $syncResult['after'],
            ],
        ]);
    }
    protected function rowHasAnyValue(array $row, array $keys): bool
    {
        foreach ($keys as $key) {
            $value = $row[$key] ?? null;
            if (is_array($value)) {
                if (!empty($value)) {
                    return true;
                }
                continue;
            }

            if (trim((string) $value) !== '') {
                return true;
            }
        }

        return false;
    }

    protected function strOrNull($value): ?string
    {
        $trimmed = trim((string) $value);
        return $trimmed === '' ? null : $trimmed;
    }

    protected function decimalOrDefault($value, float $default = 0.0): float
    {
        if ($value === null) {
            return $default;
        }

        if (is_string($value)) {
            $value = trim($value);
            if ($value === '') {
                return $default;
            }
        }

        return is_numeric($value) ? (float) $value : $default;
    }

    protected function resolveNationalEducationLevelCode($value, $fallback = null): ?int
    {
        $normalize = static function ($raw): string {
            $text = mb_strtolower(trim((string) $raw), 'UTF-8');
            return preg_replace('/\s+/u', ' ', $text) ?? $text;
        };

        $resolve = static function ($raw) use ($normalize): ?int {
            $text = trim((string) $raw);
            if ($text === '') {
                return null;
            }

            if (in_array($text, ['1', '2', '3', '4'], true)) {
                return (int) $text;
            }

            $value = $normalize($text);
            $exact = [
                'primary' => 1,
                'lower secondary' => 2,
                'upper secondary' => 3,
                'other' => 4,
                'primary_certificate' => 1,
                'lower_secondary_diploma' => 2,
                'upper_secondary_diploma' => 3,
                'vocational_certificate' => 3,
                'technical_diploma' => 3,
                'associate_degree' => 3,
                'higher_diploma' => 3,
                'bachelor_degree' => 3,
                'professional_bachelor_degree' => 3,
                'postgraduate_certificate' => 3,
                'postgraduate_diploma' => 3,
                'master_degree' => 3,
                'specialist_degree' => 3,
                'doctorate_degree' => 3,
                'postdoctorate_degree' => 3,
                'áž”áž‹áž˜' => 1,
                'áž”áž‹áž˜áž—áž¼áž˜áž·' => 2,
                'áž‘áž»ážáž·áž™áž—áž¼áž˜áž·' => 3,
                'áž•áŸ’ážŸáŸáž„áŸ—' => 4,
                'áž•áŸ’ážŸáŸáž„' => 4,
            ];

            if (isset($exact[$value])) {
                return $exact[$value];
            }

            if (str_contains($value, 'áž”áž‹áž˜áž—áž¼áž˜áž·') || str_contains($value, 'lower secondary')) {
                return 2;
            }

            if (
                str_contains($value, 'áž‘áž»ážáž·áž™áž—áž¼áž˜áž·')
                || str_contains($value, 'upper secondary')
                || str_contains($value, 'bachelor')
                || str_contains($value, 'master')
                || str_contains($value, 'doctor')
            ) {
                return 3;
            }

            if (str_contains($value, 'áž”áž‹áž˜') || str_contains($value, 'primary')) {
                return 1;
            }

            if (str_contains($value, 'áž•áŸ’ážŸáŸáž„') || str_contains($value, 'other')) {
                return 4;
            }

            return null;
        };

        return $resolve($value) ?? $resolve($fallback);
    }

    protected function resolvePayLevelKmLabel(?string $value): ?string
    {
        $input = trim((string) $value);
        if ($input === '') {
            return null;
        }

        $normalize = static function (?string $raw): string {
            $normalized = strtoupper(trim((string) $raw));
            return preg_replace('/\s+/u', '', $normalized) ?? $normalized;
        };

        $inputKey = $normalize($input);
        $payLevels = GovPayLevel::query()->get(['level_code', 'level_name_km']);
        $kmByCode = [];
        $kmByName = [];

        foreach ($payLevels as $payLevel) {
            $levelCode = trim((string) ($payLevel->level_code ?? ''));
            $levelNameKm = trim((string) ($payLevel->level_name_km ?? ''));
            $levelNameKm = preg_replace('/\.\.+/u', '.', $levelNameKm) ?? $levelNameKm;

            if ($levelNameKm !== '') {
                $kmByName[$normalize($levelNameKm)] = $levelNameKm;
            }

            if ($levelCode !== '' && $levelNameKm !== '') {
                $kmByCode[$normalize($levelCode)] = $levelNameKm;
            }
        }

        if (isset($kmByName[$inputKey])) {
            return $kmByName[$inputKey];
        }

        if (isset($kmByCode[$inputKey])) {
            return $kmByCode[$inputKey];
        }

        return $input;
    }

