    protected function resolveTransitionGroupForStatusName(string $statusName): ?string
    {
        $normalized = $this->normalizeStatusKey($statusName);
        if ($normalized === '') {
            return null;
        }

        $status = EmployeeStatus::query()
            ->get(['name_en', 'name_km', 'transition_group'])
            ->first(function ($item) use ($normalized) {
                $nameEn = $this->normalizeStatusKey((string) ($item->name_en ?? ''));
                $nameKm = $this->normalizeStatusKey((string) ($item->name_km ?? ''));
                return $normalized === $nameEn || $normalized === $nameKm;
            });

        $group = trim((string) ($status->transition_group ?? ''));

        return in_array($group, ['active', 'suspended', 'inactive'], true) ? $group : null;
    }

