            ->orderByRaw("CASE WHEN LOWER(COALESCE(name_en, '')) LIKE '%return%' THEN 0 ELSE 1 END")
            ->orderBy('sort_order')
            ->orderBy('id')
            ->first();

        if (!$status) {
